Here is the JavaScript and CSS code used in the "Liquid Glass Header" experiment (Variation 1):

JavaScript:
/* Kameleoon variation JS: Force scrolled navbar state and logo, keep glass */
(function () {
  "use strict";

  var LOGO_SRC = "images/logo-black.png";

  function initGlassOnNavbar(navbar) {
    if (!navbar || navbar.classList.contains("km-glass-nav")) return;
    navbar.classList.add("km-glass-nav");
  }

  function forceNavScroll(navbar) {
    if (!navbar) return;
    ensureClass(navbar, "nav-scroll");

    var classObserver = new MutationObserver(function () {
      ensureClass(navbar, "nav-scroll");
    });
    classObserver.observe(navbar, { attributes: true, attributeFilter: ["class"] });
  }

  function ensureClass(el, className) {
    if (el && !el.classList.contains(className)) {
      el.classList.add(className);
    }
  }

  function forceLogoBlack(root) {
    if (!root) return;

    var selectors = [
      ".navbar-brand img",
      ".navbar .logo img",
      "img.logo",
      "img[alt*=logo i]"
    ];

    var imgs = [];
    selectors.forEach(function (sel) {
      root.querySelectorAll(sel).forEach(function (img) {
        if (imgs.indexOf(img) === -1) imgs.push(img);
      });
    });

    imgs.forEach(function (img) {
      applyLogoSrc(img);
      var imgObserver = new MutationObserver(function () {
        applyLogoSrc(img);
      });
      imgObserver.observe(img, { attributes: true, attributeFilter: ["src", "srcset", "data-src"] });
    });
  }

  function applyLogoSrc(img) {
    try {
      if (!img) return;
      if (img.getAttribute("src") !== LOGO_SRC) {
        img.setAttribute("src", LOGO_SRC);
      }
      if (img.hasAttribute("srcset")) {
        img.removeAttribute("srcset");
      }
      if (img.hasAttribute("data-src")) {
        img.setAttribute("data-src", LOGO_SRC);
      }
      if (img.decode) {
        img.decode().catch(function () { /* noop */ });
      }
    } catch (e) {
      /* silently ignore */
    }
  }

  Kameleoon.API.Core.runWhenElementPresent(
    "nav.navbar.navbar-expand-lg, nav.navbar",
    function (elements) {
      elements.forEach(function (navbar) {
        initGlassOnNavbar(navbar);
        forceNavScroll(navbar);
        forceLogoBlack(navbar);
      });
    },
    undefined,
    true
  );

  function refreshOnResize() {}
  Kameleoon.API.Utils.addEventListener(window, "resize", refreshOnResize);
})();

