 * ============================================================================
 * UNIVERSAL LIFETIME ARCHIVE PULLER (COMPLETE HUB WORKFLOW ENGINE)
 * * Workflow Steps:
 * 1. [RESET] Clear Master Data Sheet: Wipes the tab and re-injects 27 headers.
 * 2. Auto-Populate Names & Dates: Resolves platform timelines on Setup tab.
 * 3. Compile Lifetime Data: Pulls performance matrix with live calculations.
 * ============================================================================
 */

const KAMELEOON_BASE_URL = "https://api.kameleoon.com";
const KAMELEOON_TOKEN_URL = `${KAMELEOON_BASE_URL}/oauth/token`;
const ALL_DEVICE_LABEL = "All";

/**
 * WORKFLOW STEP 0: MASTER SHEET PURGE & RESET
 * Completely deletes all rows and structural memory from 'Master Data' 
 * and injects the absolute 27-column enterprise schema header layout.
 */
function purgeAndResetMasterSheet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const masterSheet = ss.getSheetByName("Master Data");

  if (!masterSheet) {
    SpreadsheetApp.getUi().alert("Error: 'Master Data' tab not found. Please create it first.");
    return;
  }

  // Prompt user for confirmation before wiping everything
  const response = SpreadsheetApp.getUi().alert(
    "⚠️ Confirm Complete Reset",
    "Are you sure you want to completely delete all data rows on the Master Data sheet? This will clear the script's memory check and force a full re-pull.",
    SpreadsheetApp.getUi().ButtonSet.YES_NO
  );

  if (response !== SpreadsheetApp.getUi().Button.YES) {
    Logger.log("Reset cancelled by user.");
    return;
  }

  // Clear everything (data, formatting, hidden tracking properties)
  masterSheet.clear();

  // Inject the absolute 27-column enterprise header array explicitly into Row 1
  const headers = [
    "Fetched At", "Workbook Test ID", "Experiment ID", "Basis", "Device", "Launch Date", "Archive Date", 
    "Data Code", "Variation ID", "Variation Group", "Population", "Converted Population", "Revenue", 
    "Conversion Rate", "Revenue Per Unit", "Average Cart", "CR Uplift %", "CR Reliability", "CR Confidence Interval", 
    "RPU Uplift %", "RPU Reliability", "RPU Confidence Interval", "AOV Uplift %", "AOV Reliability", "AOV Confidence Interval", 
    "Goal ID", "Debug Path"
  ];

  masterSheet.getRange(1, 1, 1, headers.length).setValues([headers]);
  masterSheet.getRange(1, 1, 1, headers.length).setFontWeight("bold").setBackground("#f3f3f3");

  SpreadsheetApp.flush();
  SpreadsheetApp.getUi().alert("Master Data sheet successfully wiped and header schema restored! You are ready for a clean execution run.");
}

/**
 * WORKFLOW STEP 1: AUTOMATED METADATA DISCOVERY
 */
function autoPopulateTestMetadata() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const setupSheet = ss.getSheetByName("Setup");

  if (!setupSheet) {
    SpreadsheetApp.getUi().alert("Error: 'Setup' tab not found.");
    return;
  }

  const lastRow = setupSheet.getLastRow();
  if (lastRow < 5) {
    SpreadsheetApp.getUi().alert("No rows found starting at Row 5.");
    return;
  }

  setupSheet.getRange("B4:D4").setValues([["Cleaned Platform Name", "Launch Date (From)", "Archive Date (To)"]]).setFontWeight("bold");

  const idValues = setupSheet.getRange(5, 1, lastRow - 4, 1).getValues();
  let token;
  try { token = getKameleoonAccessToken_(); } catch(e) {
    SpreadsheetApp.getUi().alert("Authentication Failed. Verify your script properties.");
    return;
  }

  for (let i = 0; i < idValues.length; i++) {
    const rawId = String(idValues[i][0]).trim();
    const currentRow = 5 + i;

    if (!rawId || rawId === "" || rawId === "N/A" || rawId === "null" || rawId.startsWith("[")) continue;

    try {
      const url = `${KAMELEOON_BASE_URL}/experiments/${encodeURIComponent(rawId)}`;
      const response = UrlFetchApp.fetch(url, {
        method: "get", headers: { Authorization: `Bearer ${token}`, Accept: "application/json" }, muteHttpExceptions: true
      });

      if (response.getResponseCode() === 200) {
        const json = JSON.parse(response.getContentText());
        const parseIsoDate = (isoStr) => {
          if (!isoStr) return "";
          return Utilities.formatDate(new Date(isoStr), Session.getScriptTimeZone(), "dd/MM/yyyy");
        };

        const platformName = json.name || "Unnamed Experiment";
        const launchDate = parseIsoDate(json.dateStarted || json.startDate || json.createdAt);
        const archiveDate = parseIsoDate(json.dateEnded || json.stopDate || json.updatedAt);

        setupSheet.getRange(currentRow, 2, 1, 3).setValues([[platformName, launchDate, archiveDate]]);
      }
    } catch(err) {}
    Utilities.sleep(100);
  }
  SpreadsheetApp.flush();
}

/**
 * WORKFLOW STEP 2: MASTER PERFORMANCE DATA COMPILER WITH FALLBACK PATHS
 */
function runCuratedLifetimeWriteupPull() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const setupSheet = ss.getSheetByName("Setup");
  const masterSheet = ss.getSheetByName("Master Data");

  if (!setupSheet || !masterSheet) {
    SpreadsheetApp.getUi().alert("Error: Ensure both 'Setup' and 'Master Data' tabs exist.");
    return;
  }

  const lastRowSetup = setupSheet.getLastRow();
  if (lastRowSetup < 5) {
    SpreadsheetApp.getUi().alert("Error: No data rows found on Setup tab.");
    return;
  }

  const setupData = setupSheet.getRange(5, 1, lastRowSetup - 4, 4).getValues();

  const completedIds = new Set();
  if (masterSheet.getLastRow() > 1) {
    const existingMasterRows = masterSheet.getRange(2, 3, masterSheet.getLastRow() - 1, 1).getValues();
    existingMasterRows.forEach(row => { if(row[0]) completedIds.add(String(row[0]).trim()); });
  }

  const bases = [{ basis: "visit", visitorData: false }, { basis: "visitor", visitorData: true }];
  const devices = ["ALL", "DESKTOP", "PHONE", "TABLET", "OTHERS"];
  const formattedToday = Utilities.formatDate(new Date(), Session.getScriptTimeZone(), "dd/MM/yyyy");

  let newlyProcessedCount = 0;

  for (let i = 0; i < setupData.length; i++) {
    const expId = String(setupData[i][0]).trim();
    const testName = String(setupData[i][1]).trim();
    const launchDate = String(setupData[i][2]).trim();
    const archiveDate = String(setupData[i][3]).trim();

    if (!expId || expId === "" || expId === "N/A" || expId.startsWith("[")) continue;
    if (completedIds.has(expId)) continue;

    try {
      const token = getKameleoonAccessToken_();
      const meta = fetchExperimentMetaDetails_(expId, token);

      Logger.log(`[PULL ENGINE] Processing Unified Pathing Sync for: ${expId}`);
      const currentTestRows = [];

      bases.forEach(mode => {
        devices.forEach(device => {
          const deviceLabel = device === "ALL" ? ALL_DEVICE_LABEL : device;

          try {
            let requestResponse = requestExperimentResults_(expId, mode.visitorData, device, meta.mainGoalId, token);
            let dataCode = extractDataCode_(requestResponse);

            if (!dataCode) {
              requestResponse = requestFeatureFlagResults_(expId, mode.visitorData, device, meta.mainGoalId, token);
              dataCode = extractDataCode_(requestResponse);
            }

            if (dataCode) {
              const resultResponse = waitForResultsReady_(dataCode, token);
              const root = resultResponse.data || resultResponse;
              const variationData = root.variationData || {};

              let controlKey = Object.keys(variationData).find(k => k === "_reference" || k === "control" || k === "0");
              if (!controlKey && Object.keys(variationData).length > 0) {
                controlKey = Object.keys(variationData).sort()[0];
              }

              const controlNode = variationData[controlKey];
              const controlGeneral = findGeneralDataDeep_(controlNode);
              let controlMetrics = null;

              if (controlGeneral) {
                const controlGoal = controlGeneral.goalsData?.[meta.mainGoalId] || findFirstGoalNode_(controlGeneral.goalsData) || {};
                const cPop = mode.basis === "visitor" ? (controlGeneral.visitorCount || controlGeneral.visitCount || 0) : (controlGeneral.visitCount || controlGeneral.visitorCount || 0);
                const cConv = mode.basis === "visitor" ? (controlGoal.convertedVisitorCount || controlGoal.convertedVisitCount || controlGoal.conversionCount || 0) : (controlGoal.convertedVisitCount || controlGoal.convertedVisitorCount || controlGoal.conversionCount || 0);
                const cRev = controlGoal.revenueCount || controlGoal.revenue || controlGoal.globalRevenue || 0;

                controlMetrics = {
                  pop: cPop, conv: cConv, rev: cRev,
                  cr: controlGoal.conversionRate || (cPop > 0 ? cConv / cPop : 0),
                  rpu: controlGoal.revenuePerVisit || controlGoal.revenuePerVisitor || (cPop > 0 ? cRev / cPop : 0),
                  aov: controlGoal.averageCart || controlGoal.averageBasket || (cConv > 0 ? cRev / cConv : 0)
                };

                currentTestRows.push([
                  formattedToday, testName, expId, mode.basis, deviceLabel, launchDate || meta.launchDate, archiveDate || meta.archiveDate, 
                  dataCode, controlKey, "Control (Original)", controlMetrics.pop, controlMetrics.conv, controlMetrics.rev,
                  controlMetrics.cr, controlMetrics.rpu, controlMetrics.aov,
                  0, "N/A", "", 0, "N/A", "", 0, "N/A", "", meta.mainGoalId, "root.variationData._reference"
                ]);
              }

              Object.keys(variationData).forEach(varId => {
                if (varId === controlKey) return;

                const varNode = variationData[varId];
                const generalData = findGeneralDataDeep_(varNode);

                if (generalData) {
                  const goalNode = generalData.goalsData?.[meta.mainGoalId] || findFirstGoalNode_(generalData.goalsData) || {};

                  const pop = mode.basis === "visitor" ? (generalData.visitorCount || generalData.visitCount || 0) : (generalData.visitCount || generalData.visitorCount || 0);
                  const conv = mode.basis === "visitor" ? (goalNode.convertedVisitorCount || goalNode.convertedVisitCount || goalNode.conversionCount || 0) : (goalNode.convertedVisitCount || goalNode.convertedVisitorCount || goalNode.conversionCount || 0);
                  const rev = goalNode.revenueCount || goalNode.revenue || goalNode.globalRevenue || 0;

                  const crValue = goalNode.conversionRate || (pop > 0 ? conv / pop : 0);
                  const rpuValue = goalNode.revenuePerVisit || goalNode.revenuePerVisitor || (pop > 0 ? rev / pop : 0);
                  const aovValue = goalNode.averageCart || goalNode.averageBasket || (conv > 0 ? rev / conv : 0);

                  const nativeReliability = goalNode.reliability !== undefined ? (goalNode.reliability / 100) : "N/A";
                  const nativeCrUplift = goalNode.improvementRate !== undefined ? (goalNode.improvementRate / 100) : ((controlMetrics?.cr > 0) ? (crValue - controlMetrics.cr) / controlMetrics.cr : 0);
                  const nativeCrInterval = formatNativeInterval_(goalNode.improvementRange);

                  const calcUplift = (tVal, cVal) => { if (!cVal || cVal === 0) return 0; return (tVal - cVal) / cVal; };
                  const nativeRpuUplift = goalNode.continuousMetrics?.revenuePerVisit?.improvementRate !== undefined ? goalNode.continuousMetrics.revenuePerVisit.improvementRate : calcUplift(rpuValue, controlMetrics?.rpu);
                  const nativeRpuReliability = goalNode.continuousMetrics?.revenuePerVisit?.reliability !== undefined ? goalNode.continuousMetrics.revenuePerVisit.reliability : "N/A";
                  const nativeRpuInterval = formatContinuousInterval_(goalNode.continuousMetrics?.revenuePerVisit);

                  const nativeAovUplift = goalNode.continuousMetrics?.averageCart?.improvementRate !== undefined ? goalNode.continuousMetrics.averageCart.improvementRate : calcUplift(aovValue, controlMetrics?.aov);
                  const nativeAovReliability = goalNode.continuousMetrics?.averageCart?.reliability !== undefined ? goalNode.continuousMetrics.averageCart.reliability : "N/A";
                  const nativeAovInterval = formatContinuousInterval_(goalNode.continuousMetrics?.averageCart);

                  currentTestRows.push([
                    formattedToday, testName, expId, mode.basis, deviceLabel, launchDate || meta.launchDate, archiveDate || meta.archiveDate, 
                    dataCode, varId, `Variation Group ID: ${varId}`, pop, conv, rev, crValue, rpuValue, aovValue,
                    nativeCrUplift, nativeReliability, nativeCrInterval,
                    nativeRpuUplift, nativeRpuReliability, nativeRpuInterval,
                    nativeAovUplift, nativeAovReliability, nativeAovInterval,
                    meta.mainGoalId, `root.variationData.${varId}`
                  ]);
                }
              });
            }
          } catch (e) {
            Logger.log(`Segment loop error skipped on ID ${expId} [${deviceLabel}]: ${e.message}`);
          }
        });
      });

      if (currentTestRows.length > 0) {
        masterSheet.getRange(masterSheet.getLastRow() + 1, 1, currentTestRows.length, currentTestRows[0].length).setValues(currentTestRows);
        SpreadsheetApp.flush();
      }

      newlyProcessedCount++;
      Utilities.sleep(500);

    } catch (e) {
      Logger.log(`Failed execution run on Test ${expId}: ${e.message}`);
    }
  }

  if (newlyProcessedCount > 0) {
    SpreadsheetApp.getUi().alert("Matrix sync completely complete! All data rows printed smoothly.");
  } else {
    SpreadsheetApp.getUi().alert("All tests listed are already showing in your Master Data worksheet template.");
  }
}

/**
 * PATH TRAVERSAL HELPER ENGINE
 */
function formatNativeInterval_(rangeObj) {
  if (!rangeObj || rangeObj.min === undefined || rangeObj.max === undefined) return "";
  return `[${rangeObj.min.toFixed(2)}%; ${rangeObj.max.toFixed(2)}%]`;
}

function formatContinuousInterval_(metricObj) {
  if (!metricObj || metricObj.lowerBound === undefined || metricObj.upperBound === undefined) return "";
  return `[${(metricObj.lowerBound * 100).toFixed(2)}%; ${(metricObj.upperBound * 100).toFixed(2)}%]`;
}

function findGeneralDataDeep_(node) {
  if (!node || typeof node !== "object") return null;
  if (node.goalsData && (node.visitCount !== undefined || node.visitorCount !== undefined)) return node;
  if (node.generalData && node.generalData.goalsData) return node.generalData;
  const keys = Object.keys(node);
  for (const key of keys) {
    const result = findGeneralDataDeep_(node[key]);
    if (result) return result;
  }
  return null;
}

function findFirstGoalNode_(goalsData) {
  if (!goalsData || typeof goalsData !== "object") return null;
  const keys = Object.keys(goalsData);
  for (const key of keys) {
    if (goalsData[key] && typeof goalsData[key] === "object") return goalsData[key];
  }
  return null;
}

/**
 * METADATA DISCOVERY HANDSHAKE
 */
function fetchExperimentMetaDetails_(experimentId, token) {
  const url = `${KAMELEOON_BASE_URL}/experiments/${encodeURIComponent(experimentId)}`;
  const defaultMeta = { mainGoalId: 0, launchDate: "", archiveDate: "" };
  const response = UrlFetchApp.fetch(url, { method: "get", headers: { Authorization: `Bearer ${token}`, Accept: "application/json" }, muteHttpExceptions: true });
  if (response.getResponseCode() !== 200) return defaultMeta;
  const json = JSON.parse(response.getContentText());
  const formatDateString = (isoString) => {
    if (!isoString) return "";
    try { return Utilities.formatDate(new Date(isoString), Session.getScriptTimeZone(), "dd/MM/yyyy"); } catch(e) { return ""; }
  };
  return {
    mainGoalId: json.mainGoalId ? Number(json.mainGoalId) : 0,
    launchDate: formatDateString(json.dateStarted || json.startDate || json.createdAt),
    archiveDate: formatDateString(json.dateEnded || json.stopDate || json.updatedAt)
  };
}

function getKameleoonAccessToken_() {
  const props = PropertiesService.getScriptProperties();
  const response = UrlFetchApp.fetch(KAMELEOON_TOKEN_URL, {
    method: "post", contentType: "application/x-www-form-urlencoded",
    payload: { grant_type: "client_credentials", client_id: props.getProperty("KAMELEOON_CLIENT_ID"), client_secret: props.getProperty("KAMELEOON_CLIENT_SECRET") }
  });
  return JSON.parse(response.getContentText()).access_token;
}

function requestExperimentResults_(id, visitorData, device, goalId, token) {
  return executePostPayload_(`${KAMELEOON_BASE_URL}/experiments/${encodeURIComponent(id)}/results`, visitorData, device, goalId, token);
}

function requestFeatureFlagResults_(id, visitorData, device, goalId, token) {
  return executePostPayload_(`${KAMELEOON_BASE_URL}/feature-flags/${encodeURIComponent(id)}/results`, visitorData, device, goalId, token);
}

function executePostPayload_(url, visitorData, device, goalId, token) {
  const body = {
    "visitorData": !!visitorData, "allVariationsData": true, "bayesian": true, "sequentialTesting": false, "enabledMultipleTesting": false,
    "conversionType": "CONVERTED_VISITS", "goalsIds": [Number(goalId)], "referenceVariationId": "0"
  };
  if (device && device !== "ALL") { body.filters = [{ type: "DEVICE_TYPE", values: [device], include: true }]; }
  const response = UrlFetchApp.fetch(url, { method: "post", contentType: "application/json", headers: { Authorization: `Bearer ${token}`, Accept: "application/json" }, payload: JSON.stringify(body), muteHttpExceptions: true });
  return JSON.parse(response.getContentText());
}

function waitForResultsReady_(dataCode, token) {
  const url = `${KAMELEOON_BASE_URL}/results?dataCode=${encodeURIComponent(dataCode)}&refresh=false`;
  for (let i = 0; i < 6; i++) {
