    let legacyUrl = `https://api.kameleoon.com/experiments?size=500`; // No v=2.0 tag forces legacy table lookup
    if (siteId) legacyUrl += `&siteId=${encodeURIComponent(siteId)}`;

    Logger.log(`Querying Stream 1 (Legacy Web Testing Registry)...`);
    const legacyResponse = UrlFetchApp.fetch(legacyUrl, {
      method: "get", headers: { Authorization: `Bearer ${token}`, Accept: "application/json" }, muteHttpExceptions: true
    });

    if (legacyResponse.getResponseCode() === 200) {
      const rawLegacy = JSON.parse(legacyResponse.getContentText());
      const legacyTests = Array.isArray(rawLegacy) ? rawLegacy : (rawLegacy.experiments || rawLegacy.data || []);
      Logger.log(`Stream 1 parsed successfully. Found ${legacyTests.length} legacy entries.`);

      legacyTests.forEach(test => {
        if (!test.id || processedIds.has(test.id)) return;
        const status = String(test.status || "").toLowerCase();

        if (status === "stopped" || status === "paused" || test.isArchived === true) {
          processedIds.add(test.id);
          let allocations = "";
          if (test.deviations && typeof test.deviations === "object") {
            allocations = Object.keys(test.deviations).map(k => `${k === "origin" ? "Control" : "Var " + k}: ${(test.deviations[k] * 100).toFixed(0)}%`).join(" | ");
          }
          combinedRegistry.push([
            test.id, test.name || "Unnamed Legacy Test", test.status || "Stopped", `Web / ${test.type || "Classic"}`,
            parseIsoDate(test.dateStarted || test.startDate || test.createdAt),
            parseIsoDate(test.dateEnded || test.stopDate || test.updatedAt),
            test.mainGoalId || "N/A", allocations
          ]);
        }
      });
    }
  } catch(e) { Logger.log("Error reading legacy table: " + e.message); }

  // --------------------------------------------------------------------------
  // STREAM 2: FETCH MODERN V2 TABLE (DEVELOPER / FEATURE FLAGS)
  // --------------------------------------------------------------------------
  try {
    let modernUrl = `https://api.kameleoon.com/experiments?v=2.0&size=500`;
    if (siteId) modernUrl += `&siteId=${encodeURIComponent(siteId)}`;

    Logger.log(`Querying Stream 2 (Modern Feature Testing Registry)...`);
    const modernResponse = UrlFetchApp.fetch(modernUrl, {
      method: "get", headers: { Authorization: `Bearer ${token}`, Accept: "application/json" }, muteHttpExceptions: true
    });

    if (modernResponse.getResponseCode() === 200) {
      const rawModern = JSON.parse(modernResponse.getContentText());
      const modernTests = Array.isArray(rawModern) ? rawModern : (rawModern.experiments || rawModern.data || []);
      Logger.log(`Stream 2 parsed successfully. Found ${modernTests.length} modern entries.`);

      modernTests.forEach(test => {
        if (!test.id || processedIds.has(test.id)) return;
        const status = String(test.status || "").toLowerCase();

        if (status === "stopped" || status === "paused" || test.isArchived === true) {
          processedIds.add(test.id);
          let allocations = "";
          if (test.deviations && typeof test.deviations === "object") {
            allocations = Object.keys(test.deviations).map(k => `${k === "origin" ? "Control" : "Var " + k}: ${(test.deviations[k] * 100).toFixed(0)}%`).join(" | ");
          }
          combinedRegistry.push([
            test.id, test.name || "Unnamed Modern Test", test.status || "Stopped", `Feature Flag / ${test.type || "Developer"}`,
            parseIsoDate(test.dateStarted || test.startDate || test.createdAt),
            parseIsoDate(test.dateEnded || test.stopDate || test.updatedAt),
            test.mainGoalId || "N/A", allocations
          ]);
        }
      });
    }
  } catch(e) { Logger.log("Error reading modern table: " + e.message); }

  // --------------------------------------------------------------------------
  // PARSE COMPLETED MATRIX CORRECTIONS TO TAB
  // --------------------------------------------------------------------------
  if (combinedRegistry.length > 0) {
    combinedRegistry.sort((a, b) => b[0] - a[0]);
    inventorySheet.getRange(2, 1, combinedRegistry.length, combinedRegistry[0].length).setValues(combinedRegistry);
    inventorySheet.autoResizeColumns(1, headers.length);
    inventorySheet.getRange(2, 1, combinedRegistry.length, headers.length).setBorder(true, true, true, true, true, true, "#cccccc", SpreadsheetApp.BorderStyle.SOLID);
    Logger.log(`Successfully outputted a total of ${combinedRegistry.length} compiled historical experiments.`);
  } else {
    Logger.log("Both target ledger tables returned zero results.");
  }
}

